def solve(*args):
    if not args:
        return None

    # Assuming the first argument is the target value and the rest are the numbers to check
    target = args[0]
    numbers = args[1:]

    if not isinstance(target, (int, float)) or not all(isinstance(num, (int, float)) for num in numbers):
        raise ValueError("All inputs must be numbers")

    # Check if any number in the list equals the target
    for number in numbers:
        if number == target:
            return True

    return False
